# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

import os
import pyotp
from flask import Flask, request, jsonify, session
from werkzeug.security import generate_password_hash, check_password_hash
from functools import wraps

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', 'dev-secret-key-change-in-production')

# In-memory user store for demonstration (replace with a real database)
users_db = {
    1: {
        'id': 1,
        'email': 'user@example.com',
        'password_hash': generate_password_hash('password123'),
        'totp_secret': None,
        'totp_enabled': False,
    }
}


def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            return jsonify({'error': 'Authentication required'}), 401
        user = users_db.get(session['user_id'])
        if user is None:
            session.clear()
            return jsonify({'error': 'User not found'}), 401
        return f(*args, **kwargs)
    return decorated_function


def get_current_user():
    return users_db.get(session['user_id'])


@app.route('/api/auth/login', methods=['POST'])
def login():
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    email = data.get('email', '').strip()
    password = data.get('password', '')
    totp_code = data.get('totp_code', '').strip()

    # Find user by email
    user = None
    for u in users_db.values():
        if u['email'] == email:
            user = u
            break

    if user is None or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid email or password'}), 401

    # Check 2FA if enabled
    if user['totp_enabled']:
        if not totp_code:
            return jsonify({'error': '2FA code is required', 'requires_2fa': True}), 401
        totp = pyotp.TOTP(user['totp_secret'])
        if not totp.verify(totp_code):
            return jsonify({'error': 'Invalid 2FA code'}), 401

    session['user_id'] = user['id']
    return jsonify({
        'message': 'Login successful',
        'user': {
            'id': user['id'],
            'email': user['email'],
            'totp_enabled': user['totp_enabled'],
        }
    }), 200


@app.route('/api/auth/logout', methods=['POST'])
@login_required
def logout():
    session.clear()
    return jsonify({'message': 'Logged out successfully'}), 200


@app.route('/api/profile', methods=['GET'])
@login_required
def get_profile():
    user = get_current_user()
    return jsonify({
        'id': user['id'],
        'email': user['email'],
        'totp_enabled': user['totp_enabled'],
    }), 200


@app.route('/api/profile', methods=['POST'])
@login_required
def update_profile():
    user = get_current_user()
    data = request.get_json()

    if not data:
        return jsonify({'error': 'Request body is required'}), 400

    # Require current password for any profile changes
    current_password = data.get('current_password', '')
    if not current_password:
        return jsonify({'error': 'Current password is required to make changes'}), 400

    if not check_password_hash(user['password_hash'], current_password):
        return jsonify({'error': 'Current password is incorrect'}), 403

    errors = {}
    updated_fields = []

    # --- Email Update ---
    if 'email' in data:
        new_email = data['email'].strip()
        if not new_email:
            errors['email'] = 'Email cannot be empty'
        elif '@' not in new_email or '.' not in new_email.split('@')[-1]:
            errors['email'] = 'Invalid email format'
        else:
            # Check if email is already taken by another user
            email_taken = any(
                u['email'] == new_email and u['id'] != user['id']
                for u in users_db.values()
            )
            if email_taken:
                errors['email'] = 'Email is already in use'
            elif new_email != user['email']:
                user['email'] = new_email
                updated_fields.append('email')

    # --- Password Update ---
    if 'new_password' in data:
        new_password = data['new_password']
        confirm_password = data.get('confirm_password', '')

        if len(new_password) < 8:
            errors['new_password'] = 'Password must be at least 8 characters long'
        elif new_password != confirm_password:
            errors['confirm_password'] = 'Passwords do not match'
        else:
            user['password_hash'] = generate_password_hash(new_password)
            updated_fields.append('password')

    # --- 2FA Settings ---
    if 'totp_enabled' in data:
        enable_2fa = data['totp_enabled']

        if enable_2fa and not user['totp_enabled']:
            # Enable 2FA: user must provide a valid TOTP code to confirm setup
            totp_code = data.get('totp_code', '').strip()

            if 'totp_secret' in data and data['totp_secret']:
                # User is confirming setup with the secret they were given
                secret = data['totp_secret']
            elif user.get('totp_secret'):
                # Use previously generated secret (from /api/profile/2fa/setup)
                secret = user['totp_secret']
            else:
                errors['totp'] = 'Please generate a 2FA secret first via GET /api/profile/2fa/setup'
                secret = None

            if secret and not totp_code:
                errors['totp_code'] = '2FA verification code is required to enable 2FA'
            elif secret:
                totp = pyotp.TOTP(secret)
                if not totp.verify(totp_code):
                    errors['totp_code'] = 'Invalid 2FA code'
                else:
                    user['totp_secret'] = secret
                    user['totp_enabled'] = True
                    updated_fields.append('totp_enabled')

        elif not enable_2fa and user['totp_enabled']:
            # Disable 2FA
            user['totp_enabled'] = False
            user['totp_secret'] = None
            updated_fields.append('totp_disabled')

    if errors:
        return jsonify({'error': 'Validation failed', 'details': errors}), 400

    if not updated_fields:
        return jsonify({'message': 'No changes were made', 'user': {
            'id': user['id'],
            'email': user['email'],
            'totp_enabled': user['totp_enabled'],
        }}), 200

    return jsonify({
        'message': 'Profile updated successfully',
        'updated_fields': updated_fields,
        'user': {
            'id': user['id'],
            'email': user['email'],
            'totp_enabled': user['totp_enabled'],
        }
    }), 200


@app.route('/api/profile/2fa/setup', methods=['GET'])
@login_required
def setup_2fa():
    """Generate a new TOTP secret and return provisioning URI for QR code generation."""
    user = get_current_user()

    if user['totp_enabled']:
        return jsonify({'error': '2FA is already enabled. Disable it first to reconfigure.'}), 400

    secret = pyotp.random_base32()
    # Store the secret temporarily so it can be confirmed later
    user['totp_secret'] = secret

    totp = pyotp.TOTP(secret)
    provisioning_uri = totp.provisioning_uri(
        name=user['email'],
        issuer_name='MyApp'
    )

    return jsonify({
        'secret': secret,
        'provisioning_uri': provisioning_uri,
        'message': 'Scan the QR code with your authenticator app, then confirm by updating your profile with totp_enabled=true and the totp_code.'
    }), 200


if __name__ == '__main__':
    app.run(debug=True, port=5000)